import * as React from 'react';
import CssBaseline from '@mui/material/CssBaseline';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import Link from '@mui/material/Link';
function SimpleContainer() {
    return (
      <React.Fragment>
        <CssBaseline />
        <Container maxWidth="lg">
          <Box sx={{  height: '10vh'  }}>


          <Link
          className="App-link"
          href="https://cutekernel.com/technical-illustrations" target="_blank" rel="noopener noreferrer" underline="hover">
            {'In the meantime, you can check out my technical illustrations.'}
          </Link>              
 
          
          </Box>

          
        </Container>
      </React.Fragment>
    );
  }


export default SimpleContainer;